INSERT INTO `question` VALUES (63,17,2,3,3,'Par quelle techniques les Ă©gyptiens prĂ©servaient-ils les corps pour les inhumer ?','L\'embaumement vise Ă  conserver les corps des personnes mortes dans un Ă©tat plus ou moins proche de leur Ă©tat vivant.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL,1),(64,17,2,3,3,'Quelle couleur symbolisait la vĂ©gĂ©tation et la rĂ©gĂ©nĂ©ration en Ăgypte ancienne ?','L\'Ăgypte antique est une ancienne civilisation d\'Afrique du Nord-Est concentrĂ©e le long du cours infĂ©rieur du Nil.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL,1),(65,2,2,3,3,'Comment appelle-t-on un cadavre prĂ©servĂ© de la putrĂ©faction au moyen de l\'embaumement ?','C\'est une dessiccation naturelle dans une grotte sĂ©pulcrale qui est Ă  l\'origine de la plus ancienne momie attestĂ©e : la momie de Fallon.',NULL,NULL,'2025-08-10 14:20:14','2025-09-17 06:34:44',NULL,1),(66,17,2,3,3,'Quel concept dĂ©crit la fascination pour la culture et l\'histoire de l\'Ăgypte Antique ?','Le tourisme de masse, initiĂ© en Ăgypte par l\'agence Cook en 1869, dĂ©veloppe cette Ă©gyptomanie.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL,1),(67,17,2,3,3,'Comment appelle-t-on la Â« cuve Â» contenant le cercueil et la momie d\'un pharaon ?','En tant qu\'objet funĂ©raire, le sarcophage est prĂ©sent dans des cultures et civilisations diverses et Ă©loignĂ©es les unes des autres.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL,1),(68,17,2,3,3,'Quelle Ă©tait la premiĂšre fonction des monumentales pyramides d\'Ăgypte ?','Tombeaux des rois et des reines, la forme pyramidale de pierre accueille une ou plusieurs chambres internes reliĂ©es par des couloirs.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL,1),(69,17,2,3,3,'Quel film de 1999 a pour personnage principal la momie d\'un prĂȘtre Ă©gyptien maudit ?','Le film a donnĂ© lieu Ă  deux suites : Â« Le Retour de la momie Â» en 2001 puis Â« La Momie : La Tombe de l\'empereur Dragon Â» en 2008.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL,1),(70,17,2,3,3,'PrĂšs de quelle ville importante sont situĂ©es les grandes pyramides d\'Ăgypte ?','Le centre historique de la ville comprend le Vieux Caire ainsi que le quartier islamique, classĂ© au patrimoine mondial de l\'humanitĂ©.',NULL,NULL,'2025-08-10 14:20:14','2025-08-10 14:20:14',NULL,1),(71,17,2,3,3,'Quels films et sĂ©rie dĂ©rivĂ©e de ce film mĂȘlent science-fiction et mythologie Ă©gyptienne ?','Contrairement Ă  la plupart des films basĂ©s sur l\'exploration de la galaxie, l\'action de Â« Stargate Â» se situe Ă  notre Ă©poque.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL,1),(72,17,2,3,3,'Combien y a-t-il de grandes pyramides sur le plateau de Gizeh, classĂ© Ă  l\'UNESCO ?','Les trois plus grandes pyramides d\'Ăgypte (KhĂ©ops, KhĂ©phren et MykĂ©rinos) se situent sur la nĂ©cropole de Gizeh.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL,1),(73,17,3,3,3,'Quelle partie du visage manque-t-il au Sphinx devant les grandes pyramides de Gizeh ?','Le corps du sphinx, sculptĂ© dans la couche sous-jacente de calcaire plus tendre, pourrait ĂȘtre celui d\'un lion couchĂ©.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL,1),(74,17,3,3,3,'Quel grand pharaon fit construire une capitale Â« de loisir Â», laissant l\'administratif Ă  ThĂšbes ?','Son rĂšgne d\'une exceptionnelle durĂ©e pour l\'Ă©poque couvre Ă  lui seul la moitiĂ© du nombre d\'annĂ©es que comprend la XIXe dynastie.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL,1),(75,17,3,3,3,'Quel opĂ©ra de Verdi met en scĂšne une intrigue entre une esclave et un officier Ă©gyptien ?','N\'ayant pas assistĂ© Ă  la premiĂšre, Verdi ne fut pas satisfait par ce succĂšs parce que la salle n\'Ă©tait composĂ©e que de dignitaires invitĂ©s.',NULL,NULL,'2025-08-10 14:20:15','2025-08-10 14:20:15',NULL,1),(76,17,3,3,3,'Combien mesurent les colosses de RamsĂšs II Ă  l\'entrĂ©e du grand temple d\'Abou Simbel ?'