--
-- Table structure for table `quiz_session_answer`
--

DROP TABLE IF EXISTS `quiz_session_answer`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `quiz_session_answer` (
  `id` int NOT NULL AUTO_INCREMENT,
  `question_id` int NOT NULL,
  `proposal_id` int DEFAULT NULL,
  `created_by` int DEFAULT NULL,
  `updated_by` int DEFAULT NULL,
  `is_correct` tinyint(1) DEFAULT NULL,
  `time` int DEFAULT NULL,
  `asked_at` datetime NOT NULL COMMENT '(DC2Type:datetime_immutable)',
  `answered_at` datetime DEFAULT NULL COMMENT '(DC2Type:datetime_immutable)',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `deleted_at` datetime DEFAULT NULL,
  `quiz_session_id` binary(16) NOT NULL COMMENT '(DC2Type:uuid)',
  `score` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `IDX_DF2CD95C1E27F6BF` (`question_id`),
  KEY `IDX_DF2CD95CF4792058` (`proposal_id`),
  KEY `IDX_DF2CD95CDE12AB56` (`created_by`),
  KEY `IDX_DF2CD95C16FE72E1` (`updated_by`),
  KEY `IDX_DF2CD95C2850CBE3` (`quiz_session_id`),
  CONSTRAINT `FK_DF2CD95C16FE72E1` FOREIGN KEY (`updated_by`) REFERENCES `user` (`id`),
  CONSTRAINT `FK_DF2CD95C1E27F6BF` FOREIGN KEY (`question_id`) REFERENCES `question` (`id`),
  CONSTRAINT `FK_DF2CD95C2850CBE3` FOREIGN KEY (`quiz_session_id`) REFERENCES `quiz_session` (`id`),
  CONSTRAINT `FK_DF2CD95CDE12AB56` FOREIGN KEY (`created_by`) REFERENCES `user` (`id`),
  CONSTRAINT `FK_DF2CD95CF4792058` FOREIGN KEY (`proposal_id`) REFERENCES `proposal` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=916 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

